import os, json, re, torch
for fn in ['model.py','predict.py','train.py']:
    print('\n###', fn)
    if not os.path.exists(fn): continue
    lines=open(fn).read().splitlines()
    pats=['def default_params','class HeuristicPolicy','def act','def make_action','def run_episode','def planner_hint','def get_gps','def main']
    idx=[]
    for i,l in enumerate(lines):
        if any(l.startswith(p) for p in pats): idx.append(i)
    seen=set()
    for s in idx:
        if s in seen: continue
        seen.add(s)
        e=min(len(lines), s+70)
        print(f'-- lines {s+1}-{e} --')
        for j in range(s,e):
            print(f'{j+1}: {lines[j]}')
        print('-- end --')
ck='checkpoints/baseline/model.pt'
if os.path.exists(ck):
    obj=torch.load(ck,map_location='cpu')
    print('\nCKPT_PARAMS', json.dumps(obj.get('params',{}), sort_keys=True))
for path in ['logs/iter_23/agent1_control.json','logs/iter_17/sweep_params.json']:
    print('\nSUMMARY', path)
    if os.path.exists(path):
        data=json.load(open(path))
        if isinstance(data, list):
            from collections import defaultdict
            groups=defaultdict(list)
            for r in data:
                groups[r.get('mode') or r.get('name') or r.get('label','?')].append(r)
            for k,rs in groups.items():
                vals=[float(r.get('safe', r.get('safe_follow_steps',0))) for r in rs]
                succ=[float(r.get('succ', r.get('nav_seek_success',0))) for r in rs]
                latch=[float(r.get('latch_step', r.get('first_latch_step',-1))) for r in rs if r.get('latch_step', r.get('first_latch_step',-1)) is not None]
                print(k, 'n', len(rs), 'succ_mean', sum(succ)/len(succ), 'safe_mean', sum(vals)/len(vals), 'latch_mean', (sum(latch)/len(latch) if latch else None), 'rows', rs[:3])
        else:
            print(json.dumps(data, indent=2)[:4000])
    else:
        print('missing')
